// Build the complete Meta Cloud API payload here as a JS object so
// the HTTP node only needs JSON.stringify($json.payload). Avoids the
// newline-in-JSON parse error that happens when summaryText (which
// contains real \n chars from the prep list) is naively substituted
// into a JSON string template via n8n expression.
//
// WhatsApp template parameters reject newlines, tabs, and 5+
// consecutive spaces (error #132018). The endpoint's summaryText is
// now already a single line with format
//   "<main dishes> ｜加料：<add-ons>"
// so we can pass it straight through; safe() still scrubs as a defence.

const data = $input.first().json;

const safe = (s) => {
  if (s === undefined || s === null) return '无';
  const str = String(s)
    .replace(/\n/g, ' / ')
    .replace(/\t/g, ' ')
    .replace(/\s{5,}/g, '    ')
    .trim();
  return str.length > 0 ? str : '无';
};

// Test recipient: your own phone. Change to BowlMama's number after
// the first manual Execute Workflow round-trip confirms the template
// renders correctly.
const RECIPIENT = '60165119118';

const payload = {
  messaging_product: 'whatsapp',
  to: RECIPIENT,
  type: 'template',
  template: {
    name: 'daily_prep_summary',
    language: { code: 'zh_CN' },
    components: [
      {
        type: 'body',
        parameters: [
          { type: 'text', text: safe(data.date) },
          { type: 'text', text: safe(data.lunch?.count ?? 0) },
          { type: 'text', text: safe(data.lunch?.summaryText) },
          { type: 'text', text: safe(data.dinner?.count ?? 0) },
          { type: 'text', text: safe(data.dinner?.summaryText) },
          { type: 'text', text: safe(data.notesText) },
        ],
      },
    ],
  },
};

return [{ json: { payload, _raw: data } }];

// Surface failures clearly. Replace this with a Slack/Email node
// hooked to your own number if you want push notifications on failure.
const err = $input.first().json;
console.error('[daily-prep] WhatsApp send failed', JSON.stringify(err));
return [{ json: { error: err } }];
